// Rank candidates by rating × log(reviewCount + 1) and keep the top 5.
// Expand each surviving place to its own item, carrying the original beach id
// + Haversine distance.
const praia = $('Buscar Praias Sem Pontos').item.json;
const places = $input.item.json.places ?? [];

if (places.length === 0) {
  console.log(`Praia ${praia.id}: no nearby places`);
  return [];
}

function haversineMeters(lat1, lon1, lat2, lon2) {
  const R = 6371000;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) ** 2 +
            Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
            Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

// Pick the most specific category for our 3-way classification.
function simplifyType(types, primaryType) {
  const all = new Set([primaryType, ...(types || [])].filter(Boolean));
  if (all.has('restaurant')) return 'restaurante';
  if (all.has('bar'))        return 'bar';
  if (all.has('cafe'))       return 'cafe';
  return null;
}

const scored = places.map(pl => {
  const lat = pl.location?.latitude;
  const lng = pl.location?.longitude;
  const rating = pl.rating ?? 0;
  const reviews = pl.userRatingCount ?? 0;
  const score = rating * Math.log10(reviews + 1);
  const distance = (lat != null && lng != null)
    ? haversineMeters(praia.latitude, praia.longitude, lat, lng)
    : null;
  const photoName = pl.photos?.[0]?.name ?? null;
  return {
    place_id: pl.id,
    nome: pl.displayName?.text ?? null,
    tipo: simplifyType(pl.types, pl.primaryType),
    rating: pl.rating ?? null,
    review_count: pl.userRatingCount ?? null,
    latitude: lat ?? null,
    longitude: lng ?? null,
    distancia_metros: distance != null ? Math.round(distance) : null,
    endereco: pl.formattedAddress ?? null,
    photoName,
    score,
  };
});

// Drop places without a name or matching tipo.
const valid = scored.filter(s => s.nome && s.tipo);
valid.sort((a, b) => b.score - a.score);
const top = valid.slice(0, 5);

console.log(`Praia ${praia.id}: kept ${top.length} of ${places.length} candidates`);

return top.map(t => ({
  json: {
    praia_id: Number(praia.id),
    google_place_id: t.place_id,
    nome: t.nome,
    tipo: t.tipo,
    rating: t.rating,
    review_count: t.review_count,
    latitude: t.latitude,
    longitude: t.longitude,
    distancia_metros: t.distancia_metros,
    endereco: t.endereco,
    photoName: t.photoName,
  }
}));

// Merge resolved photo URL into the previous code node's metadata.
// If the photo call failed (no photoName, or 4xx with neverError), we still
// emit the row without a photo — the UI falls back to an emoji placeholder.
const meta = $('Ordenar e Limitar').item.json;
const body = $input.item.json ?? {};
const photoUri = body.photoUri ?? null;

return {
  json: {
    praia_id: meta.praia_id,
    google_place_id: meta.google_place_id,
    nome: meta.nome,
    tipo: meta.tipo,
    rating: meta.rating,
    review_count: meta.review_count,
    foto_url: photoUri,
    foto_attr: null,
    latitude: meta.latitude,
    longitude: meta.longitude,
    distancia_metros: meta.distancia_metros,
    endereco: meta.endereco,
  }
};

// Build bulk SQL: replace pontos_interesse for beaches that returned any,
// AND mark every processed beach as verified (so beaches with zero nearby
// places don't get re-fetched on the next run).
const rows = $input.all().map(i => i.json);
const allCandidates = $('Buscar Praias Sem Pontos').all().map(i => i.json);
const processedIds = [...new Set(allCandidates.map(c => Number(c.id)))];

if (processedIds.length === 0) {
  console.log('No beaches to verify');
  return [];
}

const esc = (v) => v == null ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
const num = (v) => v == null ? 'NULL' : String(Number(v));

let sql = '';

if (rows.length > 0) {
  const praiaIdsWithPontos = [...new Set(rows.map(r => Number(r.praia_id)))];
  const values = rows.map(r =>
    `(${num(r.praia_id)}, ${esc(r.google_place_id)}, ${esc(r.nome)}, ${esc(r.tipo)}, ${num(r.rating)}, ${num(r.review_count)}, ${esc(r.foto_url)}, ${esc(r.foto_attr)}, ${num(r.latitude)}, ${num(r.longitude)}, ${num(r.distancia_metros)}, ${esc(r.endereco)})`
  ).join(',\n');
  sql += `DELETE FROM pontos_interesse WHERE praia_id IN (${praiaIdsWithPontos.join(',')});\n`;
  sql += `INSERT INTO pontos_interesse (praia_id, google_place_id, nome, tipo, rating, review_count, foto_url, foto_attr, latitude, longitude, distancia_metros, endereco) VALUES ${values}\nON CONFLICT (praia_id, google_place_id) DO NOTHING;\n`;
}

// Always mark processed beaches as verified, even if zero nearby places were found.
sql += `UPDATE praias SET pontos_verificados_em = NOW() WHERE id IN (${processedIds.join(',')});\n`;

console.log(`Will write ${rows.length} places and mark ${processedIds.length} beaches as verified`);
return [{ json: { sql, total: rows.length, praias: processedIds.length } }];
